import './App.css';

function App() {
  return (
    <div className="App">
      <header style={{ backgroundColor: '#282c34', padding: '20px', color: 'white' }}>
        <h1>GearShare</h1>
        <p>Platform Sewa Alat Olahraga</p>
      </header>
      
      <main style={{ padding: '20px' }}>
        <h2>Daftar Alat Olahraga</h2>
        <div style={{ border: '1px solid #ccc', padding: '10px', borderRadius: '8px', width: '200px' }}>
          <img src="https://via.placeholder.com/150" alt="Raket" />
          <h3>Raket Badminton</h3>
          <p>Harga: Rp 50.000 / hari</p>
          <button style={{ cursor: 'pointer' }}>Sewa Sekarang</button>
        </div>
      </main>
    </div>
  );
}

export default App;
